import type { NavNode, NavNodeType } from '@shared/types'
import { useMemo, useState } from 'react'

const NODE_TYPES: NavNodeType[] = [
  'room',
  'entrance',
  'elevator',
  'stairs',
  'ramp',
  'restroom',
  'junction',
  'hallway',
  'landmark',
]
type SortField = 'label' | 'type' | 'floor'

interface NodeDataTableProps {
  nodes: NavNode[]
  selectedNodeId: string | null
  onUpdateNode: (id: string, updates: Partial<NavNode>) => void
  onDeleteNode: (id: string) => void
  onSelectNode: (id: string) => void
}

export function NodeDataTable({
  nodes,
  selectedNodeId,
  onUpdateNode,
  onDeleteNode,
  onSelectNode,
}: NodeDataTableProps) {
  const [sortField, setSortField] = useState<SortField>('label')
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc')
  const [filterText, setFilterText] = useState('')
  const [filterType, setFilterType] = useState<NavNodeType | 'all'>('all')
  const [editingCell, setEditingCell] = useState<{
    rowId: string
    field: 'label' | 'type' | 'roomNumber'
  } | null>(null)
  const [editValue, setEditValue] = useState('')

  function toggleSort(field: SortField) {
    if (sortField === field) setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'))
    else {
      setSortField(field)
      setSortDir('asc')
    }
  }

  const sorted = useMemo(() => {
    const filtered = nodes
      .filter((n) => n.label.toLowerCase().includes(filterText.toLowerCase()))
      .filter((n) => filterType === 'all' || n.type === filterType)
    return [...filtered].sort((a, b) => {
      const dir = sortDir === 'asc' ? 1 : -1
      if (sortField === 'label') return a.label.localeCompare(b.label) * dir
      if (sortField === 'floor') return (a.floorId - b.floorId) * dir
      return a.type.localeCompare(b.type) * dir
    })
  }, [nodes, filterText, filterType, sortField, sortDir])

  function commitEdit(node: NavNode, field: 'label' | 'type' | 'roomNumber') {
    if (field === 'label') onUpdateNode(node.id, { label: editValue })
    else if (field === 'type') onUpdateNode(node.id, { type: editValue as NavNodeType })
    else if (field === 'roomNumber') {
      const trimmed = editValue.trim()
      // Empty string treated as undefined (removes room number).
      // Spread conditional key to satisfy exactOptionalPropertyTypes.
      onUpdateNode(node.id, trimmed === '' ? {} : { roomNumber: trimmed })
    }
    setEditingCell(null)
  }

  const sortIcon = (field: SortField) =>
    sortField === field ? (sortDir === 'asc' ? ' ▲' : ' ▼') : ''

  return (
    <div className="flex flex-col gap-2 p-4">
      {/* Filter bar */}
      <div className="flex gap-2">
        <input
          type="text"
          placeholder="Filter by name..."
          value={filterText}
          onChange={(e) => setFilterText(e.target.value)}
          className="flex-1 rounded border border-gray-300 px-3 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
        />
        <select
          value={filterType}
          onChange={(e) => setFilterType(e.target.value as NavNodeType | 'all')}
          className="rounded border border-gray-300 px-2 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
        >
          <option value="all">All types</option>
          {NODE_TYPES.map((t) => (
            <option key={t} value={t}>
              {t}
            </option>
          ))}
        </select>
      </div>
      {/* Table */}
      <div className="overflow-auto rounded border border-gray-200">
        <table className="w-full text-sm">
          <thead className="bg-gray-50 text-xs uppercase text-gray-500">
            <tr>
              <th
                className="cursor-pointer px-3 py-2 text-left"
                onClick={() => toggleSort('label')}
              >
                Name{sortIcon('label')}
              </th>
              <th className="cursor-pointer px-3 py-2 text-left" onClick={() => toggleSort('type')}>
                Type{sortIcon('type')}
              </th>
              <th className="px-3 py-2 text-left">Room #</th>
              <th
                className="cursor-pointer px-3 py-2 text-left"
                onClick={() => toggleSort('floor')}
              >
                Floor{sortIcon('floor')}
              </th>
              <th className="px-3 py-2 text-left">Searchable</th>
              <th className="px-3 py-2 text-left">Actions</th>
            </tr>
          </thead>
          <tbody>
            {sorted.map((node) => (
              <tr
                key={node.id}
                onClick={() => onSelectNode(node.id)}
                className={`cursor-pointer border-t border-gray-100 hover:bg-blue-50 ${selectedNodeId === node.id ? 'bg-blue-100' : ''}`}
              >
                {/* Name — inline editable */}
                {/* biome-ignore lint/a11y/useKeyWithClickEvents: td stopPropagation only, actual interactive elements inside handle keyboard */}
                <td className="px-3 py-2" onClick={(e) => e.stopPropagation()}>
                  {editingCell?.rowId === node.id && editingCell.field === 'label' ? (
                    <input
                      // biome-ignore lint/a11y/noAutofocus: intentional focus for inline edit UX
                      autoFocus
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                      onBlur={() => commitEdit(node, 'label')}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') commitEdit(node, 'label')
                      }}
                      className="w-full rounded border border-blue-400 px-1 py-0.5 text-sm focus:outline-none"
                    />
                  ) : (
                    // biome-ignore lint/a11y/useKeyWithClickEvents: inline edit trigger; keyboard handled by surrounding input on activation
                    // biome-ignore lint/a11y/noStaticElementInteractions: span is an inline edit trigger; role would conflict with parent row click
                    <span
                      className="block cursor-text rounded px-1 py-0.5 hover:bg-blue-100"
                      onClick={() => {
                        setEditingCell({ rowId: node.id, field: 'label' })
                        setEditValue(node.label)
                      }}
                    >
                      {node.label}
                    </span>
                  )}
                </td>
                {/* Type — inline editable (dropdown) */}
                {/* biome-ignore lint/a11y/useKeyWithClickEvents: td stopPropagation only, actual interactive elements inside handle keyboard */}
                <td className="px-3 py-2" onClick={(e) => e.stopPropagation()}>
                  {editingCell?.rowId === node.id && editingCell.field === 'type' ? (
                    <select
                      // biome-ignore lint/a11y/noAutofocus: intentional focus for inline edit UX
                      autoFocus
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                      onBlur={() => commitEdit(node, 'type')}
                      className="rounded border border-blue-400 px-1 py-0.5 text-sm focus:outline-none"
                    >
                      {NODE_TYPES.map((t) => (
                        <option key={t} value={t}>
                          {t}
                        </option>
                      ))}
                    </select>
                  ) : (
                    // biome-ignore lint/a11y/useKeyWithClickEvents: inline edit trigger; keyboard handled by surrounding select on activation
                    // biome-ignore lint/a11y/noStaticElementInteractions: span is an inline edit trigger; role would conflict with parent row click
                    <span
                      className="block cursor-pointer rounded px-1 py-0.5 hover:bg-blue-100"
                      onClick={() => {
                        setEditingCell({ rowId: node.id, field: 'type' })
                        setEditValue(node.type)
                      }}
                    >
                      {node.type}
                    </span>
                  )}
                </td>
                {/* Room # — inline editable */}
                {/* biome-ignore lint/a11y/useKeyWithClickEvents: td stopPropagation only, actual interactive elements inside handle keyboard */}
                <td className="px-3 py-2" onClick={(e) => e.stopPropagation()}>
                  {editingCell?.rowId === node.id && editingCell.field === 'roomNumber' ? (
                    <input
                      // biome-ignore lint/a11y/noAutofocus: intentional focus for inline edit UX
                      autoFocus
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                      onBlur={() => commitEdit(node, 'roomNumber')}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') commitEdit(node, 'roomNumber')
                        if (e.key === 'Escape') setEditingCell(null)
                      }}
                      className="w-full rounded border border-blue-400 px-1 py-0.5 text-sm focus:outline-none"
                    />
                  ) : (
                    // biome-ignore lint/a11y/useKeyWithClickEvents: inline edit trigger; keyboard handled by surrounding input on activation
                    // biome-ignore lint/a11y/noStaticElementInteractions: span is an inline edit trigger
                    <span
                      className="block cursor-text rounded px-1 py-0.5 text-gray-500 hover:bg-blue-100"
                      onClick={() => {
                        setEditingCell({ rowId: node.id, field: 'roomNumber' })
                        setEditValue(node.roomNumber ?? '')
                      }}
                    >
                      {node.roomNumber ?? '—'}
                    </span>
                  )}
                </td>
                <td className="px-3 py-2">{node.floorId}</td>
                <td className="px-3 py-2">{node.searchable ? 'Yes' : 'No'}</td>
                {/* biome-ignore lint/a11y/useKeyWithClickEvents: td stopPropagation only; button inside handles keyboard */}
                <td className="px-3 py-2" onClick={(e) => e.stopPropagation()}>
                  <button
                    type="button"
                    onClick={() => onDeleteNode(node.id)}
                    className="rounded bg-red-600 px-2 py-0.5 text-xs text-white hover:bg-red-700"
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
            {sorted.length === 0 && (
              <tr>
                <td colSpan={6} className="px-3 py-4 text-center text-gray-400">
                  No nodes match the filter
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
      <p className="text-xs text-gray-400">
        {sorted.length} of {nodes.length} nodes
      </p>
    </div>
  )
}

import type { NavEdge, NavGraph, NavNode, NavNodeType } from '@shared/types'
import Papa from 'papaparse'
import { z } from 'zod'

// ─── Zod schemas for validation ───────────────────────────────────────────────

const navNodeTypeValues: [NavNodeType, ...NavNodeType[]] = [
  'room',
  'entrance',
  'elevator',
  'stairs',
  'ramp',
  'restroom',
  'junction',
  'hallway',
  'landmark',
]

const navNodeSchema = z.object({
  id: z.string().min(1),
  x: z.number().min(0).max(1),
  y: z.number().min(0).max(1),
  label: z.string().min(1),
  type: z.enum(navNodeTypeValues),
  searchable: z.boolean(),
  floorId: z.number().int().positive(),
  roomNumber: z.string().optional(),
  description: z.string().optional(),
  accessibilityNotes: z.string().optional(),
  connectsToFloorAboveId: z.number().int().positive().optional(),
  connectsToFloorBelowId: z.number().int().positive().optional(),
  connectsToNodeAboveId: z.string().optional(),
  connectsToNodeBelowId: z.string().optional(),
})

const navEdgeSchema = z.object({
  id: z.string().min(1),
  sourceId: z.string().min(1),
  targetId: z.string().min(1),
  standardWeight: z.number().positive(),
  accessibleWeight: z.number().positive(),
  accessible: z.boolean(),
  bidirectional: z.boolean(),
  accessibilityNotes: z.string().optional(),
})

const navFloorSchema = z.object({
  id: z.number().int().positive(),
  floorNumber: z.number().int().positive(),
  imagePath: z.string().min(1),
  updatedAt: z.string().min(1),
  nodes: z.array(navNodeSchema),
  edges: z.array(navEdgeSchema),
})

const navBuildingSchema = z.object({
  id: z.number().int().positive(),
  name: z.string().min(1),
  floors: z.array(navFloorSchema),
})

const navGraphSchema = z.object({
  buildings: z.array(navBuildingSchema),
})

// ─── Download helper ──────────────────────────────────────────────────────────

function triggerDownload(content: string, mimeType: string, filename: string): void {
  const blob = new Blob([content], { type: mimeType })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = filename
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  URL.revokeObjectURL(url)
}

// ─── CSV quoting helper ───────────────────────────────────────────────────────

function toCsvRow(values: (string | number | boolean | undefined | null)[]): string {
  return values
    .map((v) => {
      const s = v == null ? '' : String(v)
      return /[,"\n\r]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s
    })
    .join(',')
}

// ─── JSON export ──────────────────────────────────────────────────────────────

/**
 * Exports nodes and edges as a NavGraph JSON file.
 * Wraps the flat editor state into a single-building/single-floor NavGraph.
 */
export function exportJson(nodes: NavNode[], edges: NavEdge[]): void {
  const graph: NavGraph = {
    buildings: [
      {
        id: 1,
        name: 'Main Building',
        floors: [
          {
            id: 1,
            floorNumber: 1,
            imagePath: 'floor-plan.png',
            updatedAt: new Date().toISOString(),
            nodes,
            edges,
          },
        ],
      },
    ],
  }
  triggerDownload(JSON.stringify(graph, null, 2), 'application/json', 'campus-graph.json')
}

// ─── CSV export ───────────────────────────────────────────────────────────────

export function exportNodesCsv(nodes: NavNode[]): void {
  const header = toCsvRow([
    'id',
    'label',
    'type',
    'floorId',
    'roomNumber',
    'searchable',
    'x',
    'y',
    'description',
    'accessibilityNotes',
  ])
  const rows = nodes.map((n) =>
    toCsvRow([
      n.id,
      n.label,
      n.type,
      n.floorId,
      n.roomNumber ?? '',
      n.searchable,
      n.x,
      n.y,
      n.description ?? '',
      n.accessibilityNotes ?? '',
    ]),
  )
  const csv = `\ufeff${[header, ...rows].join('\n')}`
  triggerDownload(csv, 'text/csv', 'nodes.csv')
}

export function exportEdgesCsv(edges: NavEdge[]): void {
  const header = toCsvRow([
    'id',
    'sourceId',
    'targetId',
    'standardWeight',
    'accessibleWeight',
    'accessible',
    'bidirectional',
    'accessibilityNotes',
  ])
  const rows = edges.map((e) =>
    toCsvRow([
      e.id,
      e.sourceId,
      e.targetId,
      e.standardWeight,
      e.accessibleWeight,
      e.accessible,
      e.bidirectional,
      e.accessibilityNotes ?? '',
    ]),
  )
  const csv = `\ufeff${[header, ...rows].join('\n')}`
  triggerDownload(csv, 'text/csv', 'edges.csv')
}

// ─── JSON import ──────────────────────────────────────────────────────────────

export type ImportResult<T> = { ok: true; data: T } | { ok: false; errors: string[] }

/**
 * Parses a NavGraph JSON string and returns the flattened nodes and edges.
 * Supports both the new multi-floor format (buildings[].floors[]) and
 * validates against the full NavGraph schema.
 */
export function handleJsonImport(
  jsonText: string,
): ImportResult<{ nodes: NavNode[]; edges: NavEdge[] }> {
  let parsed: unknown
  try {
    parsed = JSON.parse(jsonText)
  } catch {
    return { ok: false, errors: ['File is not valid JSON'] }
  }
  const result = navGraphSchema.safeParse(parsed)
  if (!result.success) {
    const errors = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`)
    return { ok: false, errors }
  }
  // Flatten buildings → floors → nodes/edges for the flat editor state
  const nodes = result.data.buildings.flatMap((b) => b.floors.flatMap((f) => f.nodes as NavNode[]))
  const edges = result.data.buildings.flatMap((b) => b.floors.flatMap((f) => f.edges as NavEdge[]))
  return { ok: true, data: { nodes, edges } }
}

// ─── CSV import ───────────────────────────────────────────────────────────────

export function parseNodesCsv(csvText: string): ImportResult<NavNode[]> {
  const result = Papa.parse<Record<string, string>>(csvText, { header: true, skipEmptyLines: true })
  const errors: string[] = []
  const nodes: NavNode[] = []

  if (result.errors.length > 0) {
    return { ok: false, errors: result.errors.map((e) => `Row ${e.row ?? '?'}: ${e.message}`) }
  }

  for (let i = 0; i < result.data.length; i++) {
    const row = result.data[i]
    if (!row) continue
    const parsed = navNodeSchema.safeParse({
      id: row.id,
      x: Number(row.x),
      y: Number(row.y),
      label: row.label,
      type: row.type,
      searchable: row.searchable === 'true',
      floorId: Number(row.floorId),
      roomNumber: row.roomNumber || undefined,
      description: row.description || undefined,
      accessibilityNotes: row.accessibilityNotes || undefined,
    })
    if (!parsed.success) {
      errors.push(
        ...parsed.error.issues.map((e) => `Row ${i + 2}: ${e.path.join('.')}: ${e.message}`),
      )
    } else {
      nodes.push(parsed.data as NavNode)
    }
  }

  if (errors.length > 0) return { ok: false, errors }
  return { ok: true, data: nodes }
}

export function parseEdgesCsv(csvText: string): ImportResult<NavEdge[]> {
  const result = Papa.parse<Record<string, string>>(csvText, { header: true, skipEmptyLines: true })
  const errors: string[] = []
  const edges: NavEdge[] = []

  if (result.errors.length > 0) {
    return { ok: false, errors: result.errors.map((e) => `Row ${e.row ?? '?'}: ${e.message}`) }
  }

  for (let i = 0; i < result.data.length; i++) {
    const row = result.data[i]
    if (!row) continue
    const parsed = navEdgeSchema.safeParse({
      id: row.id,
      sourceId: row.sourceId,
      targetId: row.targetId,
      standardWeight: Number(row.standardWeight),
      accessibleWeight: Number(row.accessibleWeight),
      accessible: row.accessible === 'true',
      bidirectional: row.bidirectional === 'true',
      accessibilityNotes: row.accessibilityNotes || undefined,
    })
    if (!parsed.success) {
      errors.push(
        ...parsed.error.issues.map((e) => `Row ${i + 2}: ${e.path.join('.')}: ${e.message}`),
      )
    } else {
      edges.push(parsed.data as NavEdge)
    }
  }

  if (errors.length > 0) return { ok: false, errors }
  return { ok: true, data: edges }
}

// ─── FileReader helper ────────────────────────────────────────────────────────

export function readFileAsText(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = (e) => resolve(e.target?.result as string)
    reader.onerror = () => reject(new Error('Failed to read file'))
    reader.readAsText(file, 'utf-8')
  })
}

/**
 * Graph construction from NavGraph JSON.
 *
 * Builds a typed ngraph.graph instance from a serialized NavGraph object,
 * handling bidirectional edge expansion and cross-floor edge synthesis.
 * Also exports a Euclidean distance utility used for edge weight calculation
 * and A* heuristic.
 */

import type { NavEdge, NavEdgeData, NavGraph, NavNode, NavNodeData } from '@shared/types'
import type { Graph } from 'ngraph.graph'
import createGraph from 'ngraph.graph'

/**
 * Flattens a multi-floor NavGraph into a single list of nodes and edges.
 *
 * Retained for the admin map editor (MapEditorCanvas.tsx) which depends on
 * this function to flatten the NavGraph before editing and re-wrap it on save.
 * This function is NOT called inside buildGraph as of Phase 17.
 */
export function flattenNavGraph(navGraph: NavGraph): { nodes: NavNode[]; edges: NavEdge[] } {
  const nodes: NavNode[] = []
  const edges: NavEdge[] = []
  for (const building of navGraph.buildings) {
    for (const floor of building.floors) {
      nodes.push(...floor.nodes)
      edges.push(...floor.edges)
    }
  }
  return { nodes, edges }
}

/**
 * Constructs a live ngraph.graph from a serialized NavGraph JSON object.
 *
 * Phase 17 implementation: iterates buildings → floors directly (no longer
 * calls flattenNavGraph internally). After all nodes and intra-floor edges
 * are added, performs a second pass to synthesize bidirectional inter-floor
 * edges from connectsToNodeAboveId on stairs, elevator, and ramp nodes.
 *
 * Inter-floor edge weights:
 * - stairs: standardWeight=0.3, accessibleWeight=Infinity, accessible=false
 * - elevator/ramp: standardWeight=0.3, accessibleWeight=0.45, accessible=true
 *
 * For each node: destructures `{ id, ...data }` and adds to graph.
 * For each intra-floor edge: adds a directed link. If `bidirectional` is true,
 * also adds the reverse directed link so both `graph.getLink(a, b)`
 * and `graph.getLink(b, a)` return a link.
 *
 * The pathfinding engine uses x, y, and weight fields for routing; extra
 * fields (floorId, connector IDs) are stored as node data and passed through.
 */
export function buildGraph(navGraph: NavGraph): Graph<NavNodeData, NavEdgeData> {
  const graph = createGraph<NavNodeData, NavEdgeData>()

  // Pass 1: add all nodes and intra-floor edges from all buildings and floors.
  for (const building of navGraph.buildings) {
    for (const floor of building.floors) {
      for (const { id, ...data } of floor.nodes) {
        graph.addNode(id, data)
      }

      for (const { id: _id, sourceId, targetId, ...data } of floor.edges) {
        // Normalize accessibleWeight to Infinity for non-accessible edges.
        // JSON cannot represent Infinity, so the serialized form uses a large
        // finite number. The graph should carry the true semantic value.
        const edgeData: NavEdgeData = data.accessible
          ? data
          : { ...data, accessibleWeight: Number.POSITIVE_INFINITY }
        graph.addLink(sourceId, targetId, edgeData)
        if (edgeData.bidirectional) {
          graph.addLink(targetId, sourceId, edgeData)
        }
      }
    }
  }

  // Pass 2: synthesize bidirectional inter-floor edges from connector nodes.
  // Only process connectsToNodeAboveId to avoid adding each pair twice
  // (the counterpart node on the floor above has connectsToNodeBelowId pointing
  // back, which would duplicate the edge if we processed both directions here).
  const processedPairs = new Set<string>()

  graph.forEachNode((node) => {
    const data = node.data
    const nodeType = data.type

    if (
      (nodeType === 'stairs' || nodeType === 'elevator' || nodeType === 'ramp') &&
      data.connectsToNodeAboveId != null
    ) {
      const targetId = data.connectsToNodeAboveId
      if (!graph.hasNode(targetId)) return

      // Build a canonical pair key (sorted) to skip duplicates.
      const pairKey = [node.id, targetId].sort().join('|')
      if (processedPairs.has(pairKey)) return
      processedPairs.add(pairKey)

      // Skip if links already exist (e.g. JSON stored inter-floor edges).
      if (graph.hasLink(node.id, targetId) || graph.hasLink(targetId, node.id)) return

      const isAccessible = nodeType === 'elevator' || nodeType === 'ramp'
      const interFloorEdge: NavEdgeData = {
        standardWeight: 0.3,
        accessibleWeight: isAccessible ? 0.45 : Number.POSITIVE_INFINITY,
        accessible: isAccessible,
        bidirectional: true,
      }

      graph.addLink(node.id, targetId, interFloorEdge)
      graph.addLink(targetId, node.id, interFloorEdge)
    }
  })

  return graph
}

/**
 * Computes Euclidean distance between two points.
 *
 * Used by:
 * - Admin editor (Phase 9) to auto-compute edge weights from node coordinates
 * - Pathfinding engine (Plan 02) as the A* heuristic function
 *
 * @param ax - X coordinate of point A
 * @param ay - Y coordinate of point A
 * @param bx - X coordinate of point B
 * @param by - Y coordinate of point B
 * @returns Euclidean distance between the two points
 */
export function calculateWeight(ax: number, ay: number, bx: number, by: number): number {
  return Math.sqrt((ax - bx) ** 2 + (ay - by) ** 2)
}
